import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { 
  Cpu, 
  LayoutDashboard, 
  Settings, 
  LogOut, 
  TrendingUp,
  Terminal
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = async () => {
    try {
      await logout();
      navigate('/login');
    } catch (err) {
      console.error("LOGOUT_SEQUENCE_FAILED", err);
    }
  };

  // Helper to check active route for Emerald highlight
  const isActive = (path) => location.pathname === path;

  return (
    <nav className="sticky top-0 z-50 w-full border-b border-white/5 backdrop-blur-md bg-[var(--bg-color)]/80">
      <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
        
        {/* 🚀 Brand Identity */}
        <Link to="/" className="flex items-center gap-3 group">
          <div className="p-2 bg-emerald-500/10 rounded-lg group-hover:bg-emerald-500/20 transition-all shadow-[0_0_15px_var(--accent-glow)]">
            <Cpu size={24} className="text-emerald-500" />
          </div>
          <div className="flex flex-col">
            <span className="text-white font-bold tracking-[0.2em] text-sm uppercase">
              Finify AI
            </span>
            <span className="text-[9px] text-white/30 uppercase tracking-widest font-mono">
              Institutional_Node
            </span>
          </div>
        </Link>

        {/* 🛰️ Navigation Hub */}
        {user && (
          <div className="hidden md:flex items-center gap-8">
            <Link 
              to="/dashboard" 
              className={`flex items-center gap-2 text-[11px] uppercase tracking-widest font-bold transition-all ${
                isActive('/dashboard') ? 'text-emerald-500' : 'text-white/40 hover:text-white'
              }`}
            >
              <LayoutDashboard size={14} /> Dashboard
            </Link>
            <Link 
              to="/generate" 
              className={`flex items-center gap-2 text-[11px] uppercase tracking-widest font-bold transition-all ${
                isActive('/generate') ? 'text-emerald-500' : 'text-white/40 hover:text-white'
              }`}
            >
              <TrendingUp size={14} /> Strategy_Engine
            </Link>
          </div>
        )}

        {/* 🛠️ System Actions */}
        <div className="flex items-center gap-6">
          {user ? (
            <div className="flex items-center gap-4">
              <div className="hidden sm:flex flex-col items-end mr-2">
                <span className="text-[10px] text-white/60 font-medium">
                  {user.fullName || 'Operator'}
                </span>
                <span className="text-[8px] text-emerald-500/60 font-mono">
                  SECURE_SESSION_ACTIVE
                </span>
              </div>
              <button 
                onClick={handleLogout}
                className="p-2 text-white/40 hover:text-red-400 transition-all hover:bg-red-400/10 rounded-lg group"
                title="Terminate Session"
              >
                <LogOut size={18} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </div>
          ) : (
            <Link 
              to="/login" 
              className="flex items-center gap-2 text-[10px] uppercase tracking-widest font-bold text-emerald-500 hover:text-emerald-400 transition-all border border-emerald-500/20 px-4 py-2 rounded-lg bg-emerald-500/5"
            >
              <Terminal size={14} /> Access_Gate
            </Link>
          )}
        </div>
      </div>
      
      {/* 📺 Visual Indicator for Active Session */}
      {user && (
        <div className="absolute bottom-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-emerald-500/40 to-transparent" />
      )}
    </nav>
  );
};

export default Navbar;
